import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';

export type ChildVm = {
  id: string;
  name: string;
  level: string;
  avatarUrl: string;
};

export type ProgressVm = {
  courseId: string;
  courseTitle: string;
  progress: number;
  lastAccess: string;
};

export type SessionVm = {
  id: string;
  title: string;
  childName: string;
  scheduledAt: string;
};

@Component({
  selector: 'app-parent-dashboard',
  standalone: true,
  imports: [CommonModule, RouterModule],
  templateUrl: './parent-dashboard.component.html',
  styleUrls: ['./parent-dashboard.component.scss']
})
export class ParentDashboardComponent {
  isLoading = signal(true);

  parentName = signal('Mme Fatima');

  children = signal<ChildVm[]>([
    { id: 'ch1', name: 'Youssef', level: '2ème année', avatarUrl: '' },
    { id: 'ch2', name: 'Sofia', level: '4ème année', avatarUrl: '' }
  ]);

  selectedChildId = signal('ch1');

  progress = signal<ProgressVm[]>([
    { courseId: 'c1', courseTitle: 'Algèbre — Bases et exercices', progress: 35, lastAccess: '2026-03-20' },
    { courseId: 'c2', courseTitle: 'Physique — Mécanique', progress: 12, lastAccess: '2026-03-19' },
    { courseId: 'c3', courseTitle: 'Français — Expression écrite', progress: 58, lastAccess: '2026-03-20' }
  ]);

  upcomingSessions = signal<SessionVm[]>([
    { id: 's1', title: 'Correction du devoir de maths', childName: 'Youssef', scheduledAt: '2026-03-22T14:00:00' },
    { id: 's2', title: 'Physique — Cinématique', childName: 'Sofia', scheduledAt: '2026-03-23T10:00:00' }
  ]);

  stats = signal({
    avgProgress: 35,
    totalCourses: 6,
    avgScore: 72,
    sessionsThisWeek: 4
  });

  constructor() {
    setTimeout(() => this.isLoading.set(false), 600);
  }

  selectChild(childId: string) {
    this.selectedChildId.set(childId);
  }

  getCompletedCourses(): number {
    return this.progress().filter(p => p.progress === 100).length;
  }

  getAverageProgress(): number {
    const progress = this.progress();
    if (progress.length === 0) return 0;
    const total = progress.reduce((acc, p) => acc + p.progress, 0);
    return Math.round(total / progress.length);
  }

  getChildInitial(name: string): string {
    return name.charAt(0);
  }
}
<div class="min-h-screen bg-[#F8F9FA] py-8">
  <div class="mx-auto w-full max-w-7xl px-4">
    <!-- Loading -->
    <div *ngIf="isLoading()" class="flex items-center justify-center py-20">
      <div class="h-12 w-12 animate-spin rounded-full border-4 border-gray-200 border-t-[#1A73E8]"></div>
    </div>

    <!-- Content -->
    <div *ngIf="!isLoading()">
      <!-- Header -->
      <div class="mb-8 overflow-hidden rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
        <div class="flex flex-col gap-4 sm:flex-row sm:items-center sm:justify-between">
          <div>
            <h1 class="text-2xl font-bold text-gray-900 sm:text-3xl">
              👋 Bonjour, {{ parentName() }} !
            </h1>
            <p class="mt-1 text-gray-600">Suivez la progression de vos enfants</p>
          </div>
          <button class="rounded-xl bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] px-4 py-2 text-sm font-semibold text-white hover:opacity-90 transition">
            📧 Contacter un professeur
          </button>
        </div>
      </div>

      <!-- Children Selector -->
      <div class="mb-8 overflow-hidden rounded-2xl border border-gray-200 bg-white p-6 shadow-sm">
        <h2 class="mb-4 text-lg font-semibold text-gray-900">👨‍👩‍👧‍👦 Sélectionner un enfant</h2>
        <div class="flex flex-wrap gap-3">
          <button 
            *ngFor="let child of children()" 
            (click)="selectChild(child.id)"
            [class]="selectedChildId() === child.id 
              ? 'border-[#1A73E8] bg-[#1A73E8]/10 text-[#1A73E8]' 
              : 'border-gray-200 bg-white text-gray-700 hover:border-gray-300'"
            class="flex items-center gap-2 rounded-xl border px-4 py-2 font-medium transition">
            <div class="h-8 w-8 rounded-full bg-gradient-to-br from-[#1A73E8] to-[#FF6D00] flex items-center justify-center text-white text-sm font-semibold">
              {{ child.name.charAt(0) }}
            </div>
            <span>{{ child.name }}</span>
            <span class="text-sm opacity-70">({{ child.level }})</span>
          </button>
        </div>
      </div>

      <!-- Stats Cards -->
      <div class="mb-8 grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <div class="flex items-center gap-3">
            <div class="flex h-10 w-10 items-center justify-center rounded-lg bg-blue-100">
              <span class="text-xl">📚</span>
            </div>
            <div>
              <p class="text-2xl font-bold text-gray-900">{{ progress().length }}</p>
              <p class="text-sm text-gray-500">Cours inscrits</p>
            </div>
          </div>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <div class="flex items-center gap-3">
            <div class="flex h-10 w-10 items-center justify-center rounded-lg bg-green-100">
              <span class="text-xl">✅</span>
            </div>
            <div>
              <p class="text-2xl font-bold text-gray-900">{{ getCompletedCourses() }}</p>
              <p class="text-sm text-gray-500">Cours terminés</p>
            </div>
          </div>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <div class="flex items-center gap-3">
            <div class="flex h-10 w-10 items-center justify-center rounded-lg bg-purple-100">
              <span class="text-xl">📊</span>
            </div>
            <div>
              <p class="text-2xl font-bold text-gray-900">{{ getAverageProgress() }}%</p>
              <p class="text-sm text-gray-500">Progression moyenne</p>
            </div>
          </div>
        </div>
        <div class="rounded-2xl border border-gray-200 bg-white p-5 shadow-sm">
          <div class="flex items-center gap-3">
            <div class="flex h-10 w-10 items-center justify-center rounded-lg bg-orange-100">
              <span class="text-xl">🎯</span>
            </div>
            <div>
              <p class="text-2xl font-bold text-gray-900">{{ upcomingSessions().length }}</p>
              <p class="text-sm text-gray-500">Sessions à venir</p>
            </div>
          </div>
        </div>
      </div>

      <!-- Course Progress -->
      <div class="mb-8 overflow-hidden rounded-2xl border border-gray-200 bg-white shadow-sm">
        <div class="p-6">
          <h2 class="mb-4 text-lg font-semibold text-gray-900">📈 Progression des cours</h2>
          <div class="space-y-4">
            <div *ngFor="let prog of progress()" class="flex items-center gap-4 p-4 rounded-xl bg-gray-50">
              <div class="flex h-12 w-12 items-center justify-center rounded-lg bg-[#1A73E8]/10">
                <span class="text-xl">📖</span>
              </div>
              <div class="flex-1">
                <h3 class="font-medium text-gray-900">{{ prog.courseTitle }}</h3>
                <div class="mt-2 flex items-center gap-2">
                  <div class="flex-1 overflow-hidden rounded-full bg-gray-200">
                    <div class="h-2 rounded-full bg-gradient-to-r from-[#1A73E8] to-[#FF6D00]" [style.width.%]="prog.progress"></div>
                  </div>
                  <span class="text-sm font-medium text-gray-600">{{ prog.progress }}%</span>
                </div>
                <p class="mt-1 text-xs text-gray-500">Dernier accès: {{ prog.lastAccess }}</p>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Upcoming Sessions -->
      <div class="overflow-hidden rounded-2xl border border-gray-200 bg-white shadow-sm">
        <div class="p-6">
          <h2 class="mb-4 text-lg font-semibold text-gray-900">📅 Sessions à venir</h2>
          <div class="space-y-3">
            <div *ngFor="let session of upcomingSessions()" class="flex items-center gap-4 p-4 rounded-xl border border-gray-200 bg-gray-50">
              <div class="flex h-12 w-12 items-center justify-center rounded-lg bg-red-100">
                <span class="text-xl">🎥</span>
              </div>
              <div class="flex-1">
                <h3 class="font-medium text-gray-900">{{ session.title }}</h3>
                <p class="text-sm text-gray-600">Pour: {{ session.childName }}</p>
                <p class="text-xs text-gray-500">{{ session.scheduledAt | date:'dd/MM/yyyy HH:mm' }}</p>
              </div>
              <button class="rounded-lg bg-[#1A73E8] px-3 py-1.5 text-sm font-medium text-white hover:bg-[#1A73E8]/90 transition">
                Voir détails
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  </div>
</div>
